My apologies, This is most certainly not an issue with the code, I am just confused and want to understand what's going on: For the `Angular` struct's distance function, it looks like it is not calculating the cosine similarity, but rather just the euclidean distance between two (normalized to unit length) vectors. 
--------------------------------------------------
For convenience, I've copied the code here:
```
  template<typename T>
  static inline T distance(const T* x, const T* y, int f) {
    // want to calculate (a/|a| - b/|b|)^2
    // = a^2 / a^2 + b^2 / b^2 - 2ab/|a||b|
    // = 2 - 2cos
    T pp = 0, qq = 0, pq = 0;
    for (int z = 0; z < f; z++, x++, y++) {
      pp += (*x) * (*x);
      qq += (*y) * (*y);
      pq += (*x) * (*y);
    }
    T ppqq = pp * qq;
    if (ppqq > 0) return 2.0 - 2.0 * pq / sqrt(ppqq);
    else return 2.0; // cos is 0
  }
```
and this is the version for `Euclidean`, which is euclidean distance between two non-normalized vectors:
```
  template<typename T>
  static inline T distance(const T* x, const T* y, int f) {
    T d = 0.0;
    for (int i = 0; i < f; i++, x++, y++)
      d += ((*x) - (*y)) * ((*x) - (*y));
    return d;
  }
```

