    "expiry": "...",
    "start": "...",
    "permission": "..."
  },
  "item2": {
    "expiry": "...",
    "start": "...",
    "permission": "..."
  },
}
```
This makes it difficult to work with with external tools like jpterm etc. An alternative structure would be:
```JSON
[
  {
    "name": "item1",
    "expiry": "...",
    "start": "...",
    "permission": "..."
  },
  {
    "name": "item2",
    "expiry": "...",
    "start": "...",
    "permission": "..."
  }
]
```
This is consistent with how object collections are handled on other resources and works much better when trying to use with tools like jpterm.

